import{_ as t,o as a,c as i,ai as o}from"./chunks/framework.Df5W0LJX.js";const u=JSON.parse(`{"title":"You Don't Own It. You Never Did.","description":"The quiet dismantling of digital ownership — and why no one is talking about it.","frontmatter":{"title":"You Don't Own It. You Never Did.","date":"2026-05-11T00:00:00.000Z","description":"The quiet dismantling of digital ownership — and why no one is talking about it.","head":[["meta",{"property":"og:title","content":"You Don't Own It. You Never Did."}],["meta",{"property":"og:description","content":"The quiet dismantling of digital ownership — and why no one is talking about it."}],["meta",{"property":"og:url","content":"https://vishnukarthik.me/blog/digital-ownership/"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://vishnukarthik.me/blog/VKP.png"}],["meta",{"name":"twitter:title","content":"You Don't Own It. You Never Did."}],["meta",{"name":"twitter:description","content":"The quiet dismantling of digital ownership — and why no one is talking about it."}],["meta",{"name":"description","content":"The quiet dismantling of digital ownership — and why no one is talking about it."}],["meta",{"property":"article:published_time","content":"2026-05-11T00:00:00.000Z"}]]},"headers":[],"relativePath":"digital-ownership.md","filePath":"digital-ownership.md"}`),r={name:"digital-ownership.md"};function n(s,e,l,h,c,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="you-don-t-own-it-you-never-did" tabindex="-1">You Don&#39;t Own It. You Never Did. <a class="header-anchor" href="#you-don-t-own-it-you-never-did" aria-label="Permalink to “You Don&#39;t Own It. You Never Did.”">​</a></h1><p>In 2007, Amazon remotely deleted copies of George Orwell&#39;s <em>1984</em> from customers&#39; Kindles without warning.</p><p>The irony was almost too on-the-nose to take seriously. But the backlash treated it as an anomaly — a corporate overreach that would not be repeated. Amazon apologized. The story faded.</p><p>It wasn&#39;t an anomaly. It was a preview.</p><hr><h2 id="the-architecture-of-impermanence" tabindex="-1">The Architecture of Impermanence <a class="header-anchor" href="#the-architecture-of-impermanence" aria-label="Permalink to “The Architecture of Impermanence”">​</a></h2><p>Ownership, in the classical sense, means something simple: possession that cannot be revoked. You buy a book, the book is yours. The seller goes bankrupt, loses interest, or changes its mind — and your copy remains, because your copy is yours.</p><p>Digital distribution systematically dismantled this structure, and we accepted the replacement because the prices were lower and the convenience was real.</p><p>What replaced ownership wasn&#39;t ownership with new branding. It was <strong>licensed access</strong> — a relationship that exists entirely at the discretion of the licensor, subject to terms of service that can be modified unilaterally, under legal frameworks designed before any of this existed.</p><p>The distinction sounds technical. The consequences are not.</p><hr><h2 id="the-vocabulary-of-disappearance" tabindex="-1">The Vocabulary of Disappearance <a class="header-anchor" href="#the-vocabulary-of-disappearance" aria-label="Permalink to “The Vocabulary of Disappearance”">​</a></h2><p>Every major digital platform has trained users to accept language that would be unacceptable in any physical transaction:</p><blockquote><p><em>&quot;Your subscription gives you access to our library.&quot;</em></p></blockquote><p>Not: your copy of this album. Not: your purchased instance of this film. <strong>Access to our library</strong> — a library the platform can restructure, shrink, or shut down entirely.</p><p>Microsoft killed its ebook store in 2019. Users lost their libraries. The workaround: Microsoft issued refunds and the books disappeared. No physical analog exists for this. No bookstore can unmake your bookshelf.</p><p>Sony shut its PlayStation Store for older consoles. Games purchased were preserved only on devices that still had them downloaded. No redownload after the closure. A purchase that expired like a coupon.</p><p>Adobe changed its terms of service in 2024, briefly claiming the right to access user content for AI training. The clause was walked back under pressure. But the mechanism — a terms update, binding without explicit consent — remained.</p><p>The vocabulary is deliberately imprecise because precision would make the transaction unacceptable.</p><hr><h2 id="what-purchase-actually-means-now" tabindex="-1">What &quot;Purchase&quot; Actually Means Now <a class="header-anchor" href="#what-purchase-actually-means-now" aria-label="Permalink to “What &quot;Purchase&quot; Actually Means Now”">​</a></h2><p>When you buy a digital movie on Apple TV, Amazon, or Google Play, you are not purchasing a file. You are purchasing a license to stream that file, through that platform, so long as:</p><ul><li>The platform continues to operate</li><li>The platform retains the rights to that content</li><li>Your account remains in good standing under their current terms</li><li>The content rights holder doesn&#39;t withdraw it</li><li>Geoblocking doesn&#39;t apply to your current location</li></ul><p>Four of those five conditions are outside your control. Two of them can change without notice.</p><p>Disney has moved content between its platforms and pulled titles from licensing deals entirely. Google Play Movies has had titles silently removed from user libraries when licensing agreements expired — replaced with nothing.</p><p>The UX presents this as a purchase. The contract is a lease. The lease is month-to-month at the provider&#39;s option.</p><hr><h2 id="the-platform-risk-nobody-prices-in" tabindex="-1">The Platform Risk Nobody Prices In <a class="header-anchor" href="#the-platform-risk-nobody-prices-in" aria-label="Permalink to “The Platform Risk Nobody Prices In”">​</a></h2><p>Every digital library is counterparty risk.</p><p>When Spotify drops artists — or raises prices, or restructures its catalog deals — your playlist survives but its contents are renegotiated underneath you. When a game studio loses its publisher, online multiplayer shuts off and the game becomes a partial artifact of what you bought.</p><p>Physical games could be traded, resold, borrowed, or simply kept working on hardware that still existed. Digital entitlements are non-transferable, non-resellable, and dependent on infrastructure the seller controls entirely.</p><p>The pricing doesn&#39;t reflect this. You pay near-physical prices for fundamentally inferior ownership structures. The value gap is enormous, and it has never been honestly disclosed in any transaction.</p><hr><h2 id="streaming-didn-t-kill-ownership-platforms-chose-to" tabindex="-1">Streaming Didn&#39;t Kill Ownership. Platforms Chose To. <a class="header-anchor" href="#streaming-didn-t-kill-ownership-platforms-chose-to" aria-label="Permalink to “Streaming Didn&#39;t Kill Ownership. Platforms Chose To.”">​</a></h2><p>The convenient argument is that streaming made ownership economically untenable. Why own when access is so cheap?</p><p>This frames the outcome as market necessity. It wasn&#39;t.</p><p>The shift from ownership to subscription was a <strong>strategic choice</strong> by platform operators to improve LTV, reduce secondary markets, and maximize leverage over both consumers and content partners. A subscription that recurs forever is worth more than a one-time purchase. A library that can be restructured is more valuable than individual titles already sold.</p><p>Consumers accepted this framing because it was presented as a better deal. Access to everything for $15/month was genuinely better than buying individual titles at $25 each — until prices climbed, libraries were fragmented across competing platforms, and the era of bundled access reassembled itself into something barely distinguishable from the cable model it supposedly replaced.</p><p>The economics of streaming were never designed around consumer interests. They were designed around subscriber lock-in.</p><hr><h2 id="the-legal-infrastructure-hasn-t-caught-up" tabindex="-1">The Legal Infrastructure Hasn&#39;t Caught Up <a class="header-anchor" href="#the-legal-infrastructure-hasn-t-caught-up" aria-label="Permalink to “The Legal Infrastructure Hasn&#39;t Caught Up”">​</a></h2><p>The intellectual property frameworks governing digital ownership were written for a world of physical media.</p><p>Copyright law distinguishes between the expression (the book, the film, the software) and the copy (your specific instance of it). You own the copy. You license the right to interact with the expression. In the physical world, the two were inseparable. Digital distribution separated them — and the law has been mostly silent on what that separation means for consumers.</p><p><strong>First-sale doctrine</strong> — the legal principle that allows you to resell, lend, or give away physical media — has been repeatedly interpreted by U.S. courts as not applying to digital goods. You cannot resell your digital movie. You cannot lend your digital book in the same way a library lends physical ones. The logic is that you don&#39;t own a copy — you own a license, and licenses don&#39;t convey the same rights.</p><p>The doctrine was written in an era when copies had physical costs. It was never updated for an era when copies are free to produce and the restriction on resale is purely a platform business decision.</p><p>The EU has moved marginally further — a 2023 ruling affirmed some consumer rights around digital purchases — but enforcement is fragmented and platform behavior has not materially changed.</p><p>Legislation has not caught up because the platforms that benefit from the status quo are among the most well-resourced lobbying operations in history.</p><hr><h2 id="the-ai-layer" tabindex="-1">The AI Layer <a class="header-anchor" href="#the-ai-layer" aria-label="Permalink to “The AI Layer”">​</a></h2><p>The next chapter of this story involves training data.</p><p>When you create content — a photo, a document, a message, a voice recording — within a platform&#39;s ecosystem, you are typically granting that platform a broad, royalty-free license to use it. Not to sell it. Not to publish it. But to use it — a term that now includes training large language models.</p><p>Most users are not aware that the content they generate within platform-operated tools is being absorbed into commercial training pipelines. The consent mechanism is a terms-of-service checkbox that appeared during account creation, years before any of this was a realistic use case.</p><p>This isn&#39;t hypothetical. Adobe, Meta, Google, and X have all updated their terms to include AI training rights. Several walked back the most explicit language under pressure. The underlying capability and legal claim remained.</p><p>The ownership question now extends beyond what you consume. It includes what you create.</p><hr><h2 id="what-persists" tabindex="-1">What Persists <a class="header-anchor" href="#what-persists" aria-label="Permalink to “What Persists”">​</a></h2><p>None of this is permanent. Several trajectories are visible:</p><p><strong>Blockchain-based ownership</strong> — NFTs failed as a speculative asset class but the underlying technical problem they tried to solve is real. A verifiable, transferable record of digital ownership that doesn&#39;t depend on a platform intermediary would structurally change this market. The execution hasn&#39;t worked. The problem hasn&#39;t gone away.</p><p><strong>Regulatory intervention</strong> — The EU&#39;s approach to digital markets has been more aggressive than the U.S. on platform power generally. A durable consumer digital ownership standard is plausible within a ten-year horizon, at least in Europe.</p><p><strong>Open source infrastructure</strong> — For software specifically, the open source ecosystem has always preserved a pathway to genuine ownership. You can fork it. You can run it locally. The AI model weights increasingly available under open licenses represent the first time this logic has applied to frontier intelligence.</p><p><strong>Physical media revival</strong> — Vinyl records came back. Film photography never fully died. There is a small but growing movement of consumers who deliberately buy physical copies of media they care about, precisely because the alternative is what it is.</p><p>None of these fully closes the gap. But they suggest that the current architecture isn&#39;t the final one.</p><hr><h2 id="the-real-stakes" tabindex="-1">The Real Stakes <a class="header-anchor" href="#the-real-stakes" aria-label="Permalink to “The Real Stakes”">​</a></h2><p>Ownership is not a purely economic concept.</p><p>What you own determines what you can guarantee. The books on your shelf will be there tomorrow regardless of any company&#39;s business decision. The ideas in them are accessible to you regardless of any platform&#39;s pricing strategy or rights negotiation. Your private library is a hedge against the instability of institutional access.</p><p>When libraries were restricted or banned historically, individuals with private collections preserved what institutions wanted gone. Digital platforms have quietly removed this redundancy from most people&#39;s lives. Your collection exists at the platform&#39;s discretion. That is not a collection — it is a rental with the aesthetics of ownership.</p><p>The design choice to make this illegible was intentional. The word &quot;purchase&quot; is in the UI because &quot;acquire a revocable license&quot; would not convert at the same rate.</p><p>Naming it clearly doesn&#39;t reverse it. But understanding the structure is the first step to making rational decisions within it.</p><p>Own what matters. Treat everything else as borrowed.</p><hr><p><em>Digital convenience was always the price of control. The terms of the deal were never on the screen.</em></p>',72)])])}const m=t(r,[["render",n]]);export{u as __pageData,m as default};
